impl Debug for Process {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        f.debug_struct("Process").field("pid", &self.pid.0).finish()
    }
}

impl Drop for Process {
    fn drop(&mut self) {
        let inner = self.inner.lock();
        for (fd, file) in inner.fd_table.iter().enumerate() {
            if file.is_some() {
                log::debug!(
                    "[Process::drop] drop fd {}, file ref cnt {}",
                    fd,
                    Arc::strong_count(file.as_ref().unwrap())
                );
            }
        }
        log::debug!("process {} died!", self.pid());
    }
}

pub struct ProcessInner {
    pub is_zombie: bool,

    pub parent: Option<Weak<Process>>,

    pub children: Vec<Arc<Process>>,

    pub threads: BTreeMap<usize, Weak<Thread>>,

    pub exit_code: i8,

