    dirfd: isize,
    path: *const u8,
    flags: OpenFlags,
) -> GeneralResult<Arc<dyn Inode>> {
    if flags.contains(OpenFlags::CREATE) {
        let (inode, path, parent) = utils::path::ffi_path2inode(dirfd, path, true)?;
        if let Some(inode) = inode {
            Ok(inode)
        } else {
            try_create_inode(parent, path, flags)
        }
    } else {
        let (inode, path, parent) = utils::path::ffi_path2inode(dirfd, path, false)?;
        if let Some(inode) = inode {
            Ok(inode)
        } else {
            try_create_inode(parent, path, flags)
        }
    }
}

pub fn path2inode_flags(
    dirfd: isize,
    path: &str,
    flags: OpenFlags,
) -> GeneralResult<Arc<dyn Inode>> {
    if flags.contains(OpenFlags::CREATE) {
        let (inode, path, parent) = utils::path::path_to_inode(dirfd, Some(path), true)?;
        if let Some(inode) = inode {
            Ok(inode)
        } else {
            try_create_inode(parent, path, flags)
        }
    } else {
        let (inode, path, parent) = utils::path::path_to_inode(dirfd, Some(path), false)?;
        if let Some(inode) = inode {
            Ok(inode)
        } else {
            try_create_inode(parent, path, flags)
        }
    }
}

fn try_create_inode(
    parent: Option<Arc<dyn Inode>>,
    path: String,
    flags: OpenFlags,
) -> GeneralResult<Arc<dyn Inode>> {
    if flags.contains(OpenFlags::CREATE) {
        let parent = match parent {
            Some(parent) => parent,
            None => {
                //wyz:我觉得不会有这种情况
                println!("[create_inode_if_need]:parent is none");
                let parent_path = utils::path::get_parent_dir(&path).unwrap();
                <dyn Inode>::lookup_from_root(&parent_path)
                    .ok()
                    .unwrap()
                    .0
                    .unwrap()
            }
        };
        let child_name = utils::path::get_name(&path);
        debug!("create file {}", path);
        let res = {
            if flags.contains(OpenFlags::DIRECTORY) {
                parent.mkdir_v(child_name, FileType::FileDIR).unwrap()
            } else {
                // TODO dev id
                parent.mknod_v(child_name, FileType::FileREG, None).unwrap()
            }
        };
        Ok(res)
    } else {
        debug!("parent dir {} doesn't exist", path);
        Err(Errno::ENOENT)
    }
}

