pub fn enable_stimer_interrupt() {
    unsafe { sie::set_stimer() }
}

#[no_mangle]
pub fn trap_return() {
    close_interrupt();

    set_user_trap_entry();

    extern "C" {
        fn user_trapret(cx: *mut TrapContext);
    }

    if let Some((errno, msg)) = check_current_signals() {
        debug!("trap_return: {}", msg);
        exit_and_terminate_all_threads(errno);
    }

    unsafe {
        user_trapret(current_trap_cx());
    }
}

